using Microsoft.AspNetCore.Mvc; namespace BarberSync.KioskWeb.Controllers; [ApiController,Route("KioskApi")] public class KioskApiController:ControllerBase{static object Env(object d,string m="Operação realizada com sucesso.")=>new{success=true,message=m,data=d};static readonly object[] Services={new{id="svc-corte",name="Corte Masculino",price=45,duration=35},new{id="svc-barba",name="Barba Tradicional",price=35,duration=25},new{id="svc-combo",name="Corte + Barba",price=75,duration=60},new{id="svc-sobrancelha",name="Sobrancelha",price=25,duration=15},new{id="svc-hidratacao",name="Hidratação Capilar",price=90,duration=45},new{id="svc-manicure",name="Manicure",price=55,duration=50}};static readonly object[] Pros={new{id="pro-rafael",name="Rafael Barber",available=true},new{id="pro-lucas",name="Lucas Navalha",available=true},new{id="pro-bruno",name="Bruno Estilo",available=true},new{id="pro-camila",name="Camila Beauty",available=true},new{id="pro-amanda",name="Amanda Nails",available=true}};[HttpGet("services")]public IActionResult ServicesGet(string? deviceCode)=>Ok(Env(Services));[HttpGet("professionals")]public IActionResult ProsGet(string? serviceId,string? deviceCode)=>Ok(Env(Pros));[HttpPost("client/find-by-phone")]public IActionResult Find([FromBody]object body)=>Ok(Env(new{id="cli-demo",name="Cliente Demo",phone="(11) 99999-0000",body}));[HttpPost("client/quick-register")]public IActionResult Register([FromBody]object body)=>Ok(Env(new{id=Guid.NewGuid(),body}));[HttpPost("payment/mock")]public IActionResult Pay([FromBody]object body)=>Ok(Env(new{transactionId=Guid.NewGuid(),authorized=true,body}));[HttpPost("review")]public IActionResult Review([FromBody]object body)=>Ok(Env(new{received=true,body}));}
